body.script:
/* =============================================================
   MONTE CARLO ENGINE
   ============================================================= */

const SPRINT_DAYS = 14;
const SEPT_END = new Date('2026-09-30T23:59:59');

/* ---- helpers ---- */
const pad = n => String(n).padStart(2, '0');
function formatDate(d) {
  const months = ['stycznia','lutego','marca','kwietnia','maja','czerwca',
                  'lipca','sierpnia','września','października','listopada','grudnia'];
  return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
}
function formatDateShort(d) {
  const months = ['sty','lut','mar','kwi','maj','cze','lip','sie','wrz','paź','lis','gru'];
  return `${d.getDate()} ${months[d.getMonth()]} '${String(d.getFullYear()).slice(2)}`;
}
function formatNumber(n, decimals=0) {
  return n.toFixed(decimals).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
}
function dateAfterSprints(startDate, sprintCount) {
  const d = new Date(startDate);
  d.setDate(d.getDate() + SPRINT_DAYS * sprintCount);
  return d;
}
function percentile(arr, p) {
  // arr should be sorted ascending
  const idx = Math.min(arr.length - 1, Math.floor(p * arr.length));
  return arr[idx];
}
function avg(arr) {
  return arr.reduce((a,b)=>a+b, 0) / arr.length;
}

/* ---- read params from DOM ---- */
function readParams() {
  const throughputRaw = document.getElementById('i-throughput').value;
  const throughput = throughputRaw.split(/[,\s]+/).map(s => parseFloat(s)).filter(n => !isNaN(n) && n >= 0);
  return {
    backlog:         parseInt(document.getElementById('i-backlog').value, 10),
    startDate:       new Date(document.getElementById('i-start').value + 'T00:00:00'),
    throughput:      throughput.length ? throughput : [4],
    scopeMin:        parseFloat(document.getElementById('i-scope-min').value) / 100,
    scopeMax:        parseFloat(document.getElementById('i-scope-max').value) / 100,
    vacFactor:       1 - parseFloat(document.getElementById('i-vac').value) / 100,
    vacSprints:      parseInt(document.getElementById('i-vac-sprints').value, 10),
    seasonalFactor:  1 - parseFloat(document.getElementById('i-seasonal').value) / 100,
    seasonalFrom:    parseInt(document.getElementById('i-seasonal-from').value, 10),
    runs:            parseInt(document.getElementById('i-runs').value, 10),
  };
}

/* ---- single simulation: returns sprints to complete + per-sprint cumulative ---- */
function simulateOnce(p, captureTrace=false, maxSprints=80) {
  const scope = 1 + p.scopeMin + Math.random() * (p.scopeMax - p.scopeMin);
  const total = p.backlog * scope;
  let done = 0;
  let sprint = 0;
  const trace = captureTrace ? [0] : null;
  while (done < total && sprint < maxSprints) {
    let base = p.throughput[Math.floor(Math.random() * p.throughput.length)];
    if (sprint < p.vacSprints) base = base * p.vacFactor;
    if (sprint >= p.seasonalFrom - 1) base = base * p.seasonalFactor;
    done += base;
    sprint += 1;
    if (captureTrace) trace.push(done);
  }
  return { sprints: sprint, total, finalDone: done, trace };
}

/* ---- full Monte Carlo run ---- */
function runMonteCarlo(p) {
  const t0 = performance.now();
  const sprints = [];
  // we need traces only for the fan chart - sample a subset for memory efficiency
  const traceSampleN = Math.min(500, p.runs);
  const traces = new Array(traceSampleN);
  const maxSprints = 80;

  // For "items by Sept 30" we need to know how many sprints fit in [start, sept30]
  const daysToSept = Math.floor((SEPT_END - p.startDate) / 86400000);
  const sprintsInSept = Math.max(0, Math.floor(daysToSept / SPRINT_DAYS));

  const itemsBySept = [];

  for (let i = 0; i < p.runs; i++) {
    const capture = i < traceSampleN;
    const r = simulateOnce(p, capture, maxSprints);
    sprints.push(r.sprints);
    if (capture) traces[i] = r.trace;

    // Items by Sept 30 = min(done_at_sprintsInSept, total)
    // We need a separate quick sim to count items, but for efficiency reuse: if captured, we have it.
    // For non-captured we need a quick recompute - but it's expensive. Instead let's compute items by sept inside simulateOnce too.
    if (capture) {
      const itemsAtSept = r.trace[Math.min(sprintsInSept, r.trace.length - 1)];
      itemsBySept.push(Math.min(itemsAtSept, r.total));
    }
  }

  // For itemsBySept across all runs, do a lightweight specialized loop
  itemsBySept.length = 0;
  for (let i = 0; i < p.runs; i++) {
    const scope = 1 + p.scopeMin + Math.random() * (p.scopeMax - p.scopeMin);
    const total = p.backlog * scope;
    let done = 0;
    for (let s = 0; s < sprintsInSept && done < total; s++) {
      let base = p.throughput[Math.floor(Math.random() * p.throughput.length)];
      if (s < p.vacSprints) base *= p.vacFactor;
      if (s >= p.seasonalFrom - 1) base *= p.seasonalFactor;
      done += base;
    }
    itemsBySept.push(Math.min(done, total));
  }

  sprints.sort((a,b)=>a-b);
  itemsBySept.sort((a,b)=>a-b);

  const result = {
    sprints,
    itemsBySept,
    traces,
    sprintsInSept,
    p50: percentile(sprints, 0.50),
    p85: percentile(sprints, 0.85),
    p95: percentile(sprints, 0.95),
    pMin: sprints[0],
    pMax: sprints[sprints.length-1],
    avg: avg(sprints),
    itemsP50: itemsBySept[Math.floor(itemsBySept.length * 0.5)],
    // for "we deliver ≥ X with 85% probability" => we want the 15th percentile (lower tail)
    itemsP85: itemsBySept[Math.floor(itemsBySept.length * 0.15)],
    itemsP95: itemsBySept[Math.floor(itemsBySept.length * 0.05)],
    itemsAvg: avg(itemsBySept),
    itemsMax: itemsBySept[itemsBySept.length - 1],
    timeMs: performance.now() - t0,
  };

  // Also compute baseline (no modifiers)
  const baseline = { sprints: [] };
  for (let i = 0; i < Math.min(5000, p.runs); i++) {
    let done = 0; let sprint = 0;
    while (done < p.backlog && sprint < maxSprints) {
      done += p.throughput[Math.floor(Math.random() * p.throughput.length)];
      sprint++;
    }
    baseline.sprints.push(sprint);
  }
  baseline.sprints.sort((a,b)=>a-b);
  baseline.p50 = percentile(baseline.sprints, 0.5);
  baseline.p85 = percentile(baseline.sprints, 0.85);
  result.baseline = baseline;

  return result;
}

/* =============================================================
   SVG CHART RENDERERS
   ============================================================= */

const tooltipEl = document.getElementById('tooltip');
function showTip(html, evt) {
  tooltipEl.innerHTML = html;
  tooltipEl.style.opacity = '1';
  positionTip(evt);
}
function positionTip(evt) {
  const x = evt.clientX + 14;
  const y = evt.clientY - 8;
  tooltipEl.style.left = x + 'px';
  tooltipEl.style.top  = y + 'px';
}
function hideTip() { tooltipEl.style.opacity = '0'; }

function clearSvg(svg) {
  while (svg.firstChild) svg.removeChild(svg.firstChild);
}
function ns(tag, attrs={}) {
  const el = document.createElementNS('http://www.w3.org/2000/svg', tag);
  for (const k in attrs) el.setAttribute(k, attrs[k]);
  return el;
}

/* ---- Histogram of completion sprints ---- */
function renderHistogram(svg, sprints, p, percentiles) {
  clearSvg(svg);
  const W = 800, H = 320;
  const margin = { top: 24, right: 24, bottom: 60, left: 56 };
  const innerW = W - margin.left - margin.right;
  const innerH = H - margin.top - margin.bottom;

  const min = sprints[0];
  const max = sprints[sprints.length - 1];
  const range = Math.max(1, max - min + 1);
  // bin per sprint
  const bins = new Array(range).fill(0);
  for (const s of sprints) bins[s - min]++;
  const maxCount = Math.max(...bins);
  const barW = innerW / range;

  const g = ns('g', { transform: `translate(${margin.left},${margin.top})` });

  // grid lines (count)
  const yTicks = 4;
  for (let i = 0; i <= yTicks; i++) {
    const y = innerH - (i / yTicks) * innerH;
    const val = Math.round((i / yTicks) * maxCount);
    g.appendChild(ns('line', { x1: 0, y1: y, x2: innerW, y2: y, class: 'grid-line' }));
    const t = ns('text', { x: -8, y: y + 4, 'text-anchor': 'end', class: 'axis-label' });
    t.textContent = formatNumber(val);
    g.appendChild(t);
  }

  // bars
  bins.forEach((count, i) => {
    const h = (count / maxCount) * innerH;
    const x = i * barW;
    const sprintNum = min + i;
    const dateStr = formatDateShort(dateAfterSprints(p.startDate, sprintNum));
    const rect = ns('rect', {
      x: x + 1,
      y: innerH - h,
      width: Math.max(1, barW - 2),
      height: h,
      fill: 'var(--ink)',
      opacity: 0.82,
    });
    rect.addEventListener('mouseenter', e => {
      rect.setAttribute('opacity', '1');
      showTip(`Sprint ${sprintNum} · ${dateStr}
${count} symulacji (${(count/sprints.length*100).toFixed(1)}%)`, e);
    });
    rect.addEventListener('mousemove', positionTip);
    rect.addEventListener('mouseleave', () => { rect.setAttribute('opacity', '0.82'); hideTip(); });
    g.appendChild(rect);
  });

  // x-axis labels (every Nth sprint)
  const xStep = Math.max(1, Math.ceil(range / 8));
  for (let i = 0; i < range; i += xStep) {
    const sprintNum = min + i;
    const date = dateAfterSprints(p.startDate, sprintNum);
    const x = i * barW + barW / 2;
    const t1 = ns('text', { x, y: innerH + 18, 'text-anchor': 'middle', class: 'axis-label' });
    t1.textContent = `s${sprintNum}`;
    g.appendChild(t1);
    const t2 = ns('text', { x, y: innerH + 34, 'text-anchor': 'middle', class: 'axis-label' });
    t2.textContent = formatDateShort(date);
    t2.setAttribute('font-size', '10');
    g.appendChild(t2);
  }

  // percentile lines
  const linesData = [
    { value: percentiles.p50, color: 'var(--p50)', label: 'P50' },
    { value: percentiles.p85, color: 'var(--p85)', label: 'P85' },
    { value: percentiles.p95, color: 'var(--p95)', label: 'P95' },
  ];
  linesData.forEach(d => {
    const x = (d.value - min + 0.5) * barW;
    g.appendChild(ns('line', {
      x1: x, y1: 0, x2: x, y2: innerH,
      stroke: d.color, 'stroke-width': 2, 'stroke-dasharray': '4 4'
    }));
    const lbl = ns('text', { x: x + 4, y: 14, class: 'axis-label', fill: d.color });
    lbl.setAttribute('font-weight', '600');
    lbl.textContent = `${d.label} · s${d.value} · ${formatDateShort(dateAfterSprints(p.startDate, d.value))}`;
    g.appendChild(lbl);
  });

  // axis title
  const axisTitle = ns('text', { x: innerW / 2, y: innerH + 54, 'text-anchor': 'middle', class: 'axis-label' });
  axisTitle.setAttribute('font-weight', '600');
  axisTitle.textContent = 'Sprint zakończenia backlogu';
  g.appendChild(axisTitle);

  const yTitle = ns('text', { class: 'axis-label' });
  yTitle.setAttribute('transform', `translate(-44, ${innerH/2}) rotate(-90)`);
  yTitle.setAttribute('text-anchor', 'middle');
  yTitle.setAttribute('font-weight', '600');
  yTitle.textContent = 'Liczba symulacji';
  g.appendChild(yTitle);

  svg.appendChild(g);
}

/* ---- CDF chart ---- */
function renderCDF(svg, sprints, p, percentiles) {
  clearSvg(svg);
  const W = 800, H = 280;
  const margin = { top: 20, right: 24, bottom: 56, left: 56 };
  const innerW = W - margin.left - margin.right;
  const innerH = H - margin.top - margin.bottom;

  const min = sprints[0];
  const max = sprints[sprints.length - 1];
  const range = Math.max(1, max - min);

  // build CDF
  const n = sprints.length;
  // unique sprint values
  const points = [];
  let i = 0;
  while (i < n) {
    const v = sprints[i];
    let j = i;
    while (j < n && sprints[j] === v) j++;
    points.push({ x: v, cdf: j / n });
    i = j;
  }

  const x = v => ((v - min) / range) * innerW;
  const y = c => innerH - c * innerH;

  const g = ns('g', { transform: `translate(${margin.left},${margin.top})` });

  // background bands
  // ≤ P50 band (0 to P50)
  const p50x = x(percentiles.p50);
  const p85x = x(percentiles.p85);
  const p95x = x(percentiles.p95);
  g.appendChild(ns('rect', { x: 0, y: 0, width: p50x, height: innerH, fill: 'var(--p50-soft)', opacity: 0.55 }));
  g.appendChild(ns('rect', { x: p50x, y: 0, width: p85x - p50x, height: innerH, fill: 'var(--p85-soft)', opacity: 0.55 }));
  g.appendChild(ns('rect', { x: p85x, y: 0, width: p95x - p85x, height: innerH, fill: 'var(--p95-soft)', opacity: 0.55 }));

  // grid
  for (let i = 0; i <= 4; i++) {
    const yc = (i / 4) * innerH;
    g.appendChild(ns('line', { x1: 0, y1: yc, x2: innerW, y2: yc, class: 'grid-line' }));
    const t = ns('text', { x: -8, y: yc + 4, 'text-anchor': 'end', class: 'axis-label' });
    t.textContent = `${(100 - i*25)}%`;
    g.appendChild(t);
  }

  // path
  let d = `M 0 ${y(0)} `;
  for (const pt of points) d += `L ${x(pt.x)} ${y(pt.cdf)} `;
  d += `L ${innerW} ${y(1)}`;
  const path = ns('path', { d, fill: 'none', stroke: 'var(--ink)', 'stroke-width': 2.2 });
  g.appendChild(path);

  // percentile markers
  [
    { p: 0.50, x: p50x, color: 'var(--p50)', label: 'P50' },
    { p: 0.85, x: p85x, color: 'var(--p85)', label: 'P85' },
    { p: 0.95, x: p95x, color: 'var(--p95)', label: 'P95' },
  ].forEach(d => {
    g.appendChild(ns('line', { x1: d.x, y1: 0, x2: d.x, y2: innerH, stroke: d.color, 'stroke-width': 1.5, 'stroke-dasharray': '3 3' }));
    g.appendChild(ns('circle', { cx: d.x, cy: y(d.p), r: 5, fill: d.color, stroke: 'var(--paper)', 'stroke-width': 2 }));
    const lbl = ns('text', { x: d.x + 6, y: y(d.p) - 8, class: 'axis-label', fill: d.color });
    lbl.setAttribute('font-weight', '600');
    lbl.textContent = `${d.label}`;
    g.appendChild(lbl);
  });

  // x ticks (sprints)
  const xStep = Math.max(1, Math.ceil(range / 8));
  for (let v = min; v <= max; v += xStep) {
    const xx = x(v);
    const date = dateAfterSprints(p.startDate, v);
    const t1 = ns('text', { x: xx, y: innerH + 18, 'text-anchor': 'middle', class: 'axis-label' });
    t1.textContent = `s${v}`;
    g.appendChild(t1);
    const t2 = ns('text', { x: xx, y: innerH + 32, 'text-anchor': 'middle', class: 'axis-label' });
    t2.textContent = formatDateShort(date);
    t2.setAttribute('font-size', '10');
    g.appendChild(t2);
  }

  // axis titles
  const yTitle = ns('text', { class: 'axis-label' });
  yTitle.setAttribute('transform', `translate(-42, ${innerH/2}) rotate(-90)`);
  yTitle.setAttribute('text-anchor', 'middle');
  yTitle.setAttribute('font-weight', '600');
  yTitle.textContent = 'P (ukończenia ≤ data)';
  g.appendChild(yTitle);

  // Hover crosshair
  const crosshair = ns('line', { x1: 0, y1: 0, x2: 0, y2: innerH, stroke: 'var(--ink)', 'stroke-width': 1, 'stroke-dasharray': '2 3', opacity: 0 });
  g.appendChild(crosshair);
  const hitArea = ns('rect', { x: 0, y: 0, width: innerW, height: innerH, fill: 'transparent' });
  hitArea.addEventListener('mousemove', e => {
    const rect = svg.getBoundingClientRect();
    const scale = rect.width / W;
    const px = (e.clientX - rect.left) / scale - margin.left;
    if (px < 0 || px > innerW) return;
    const v = Math.round(min + (px / innerW) * range);
    // find CDF value at v
    let cdfVal = 0;
    for (const pt of points) {
      if (pt.x <= v) cdfVal = pt.cdf; else break;
    }
    crosshair.setAttribute('x1', x(v));
    crosshair.setAttribute('x2', x(v));
    crosshair.setAttribute('opacity', '0.4');
    const date = dateAfterSprints(p.startDate, v);
    showTip(`Sprint ${v} · ${formatDateShort(date)}
P(ukończ. ≤ tej daty): ${(cdfVal*100).toFixed(1)}%`, e);
  });
  hitArea.addEventListener('mouseleave', () => { crosshair.setAttribute('opacity', '0'); hideTip(); });
  g.appendChild(hitArea);

  svg.appendChild(g);
}

/* ---- Fan chart of completion progress over time ---- */
function renderFan(svg, traces, p, percentiles) {
  clearSvg(svg);
  const W = 800, H = 320;
  const margin = { top: 20, right: 24, bottom: 56, left: 56 };
  const innerW = W - margin.left - margin.right;
  const innerH = H - margin.top - margin.bottom;

  // Determine sprint range to plot (up to P95)
  const maxSprint = percentiles.p95 + 1;
  // For each sprint up to maxSprint, gather completed-counts across traces
  const perSprint = new Array(maxSprint + 1).fill(null).map(() => []);
  for (const tr of traces) {
    if (!tr) continue;
    for (let s = 0; s <= maxSprint; s++) {
      const v = s < tr.length ? tr[s] : tr[tr.length - 1]; // hold at final
      perSprint[s].push(v);
    }
  }
  // sort each
  perSprint.forEach(arr => arr.sort((a,b)=>a-b));

  // determine y scale - max value
  const maxY = perSprint[maxSprint].length ? perSprint[maxSprint][perSprint[maxSprint].length-1] : p.backlog * 1.3;

  const x = s => (s / maxSprint) * innerW;
  const y = v => innerH - (v / maxY) * innerH;

  const g = ns('g', { transform: `translate(${margin.left},${margin.top})` });

  // grid
  const yTicks = 5;
  for (let i = 0; i <= yTicks; i++) {
    const yc = (i / yTicks) * innerH;
    const val = maxY * (1 - i/yTicks);
    g.appendChild(ns('line', { x1: 0, y1: yc, x2: innerW, y2: yc, class: 'grid-line' }));
    const t = ns('text', { x: -8, y: yc + 4, 'text-anchor': 'end', class: 'axis-label' });
    t.textContent = Math.round(val);
    g.appendChild(t);
  }

  // Helper to build a band polygon between two percentile arrays
  function buildBand(loP, hiP) {
    let dTop = '', dBot = '';
    for (let s = 0; s <= maxSprint; s++) {
      const arr = perSprint[s];
      if (!arr.length) continue;
      const lo = arr[Math.floor(loP * arr.length)] || 0;
      const hi = arr[Math.min(arr.length - 1, Math.floor(hiP * arr.length))] || 0;
      dTop += `${s === 0 ? 'M' : 'L'} ${x(s)} ${y(hi)} `;
      dBot = `L ${x(s)} ${y(lo)} ` + dBot;
    }
    return dTop + dBot + 'Z';
  }

  // Bands from outer to inner
  g.appendChild(ns('path', { d: buildBand(0.05, 0.95), fill: 'var(--p95-soft)', opacity: 0.75 }));
  g.appendChild(ns('path', { d: buildBand(0.15, 0.85), fill: 'var(--p85-soft)', opacity: 0.85 }));
  g.appendChild(ns('path', { d: buildBand(0.25, 0.75), fill: 'var(--p50-soft)', opacity: 0.85 }));

  // Median line
  let medianD = '';
  for (let s = 0; s <= maxSprint; s++) {
    const arr = perSprint[s];
    if (!arr.length) continue;
    const med = arr[Math.floor(0.5 * arr.length)] || 0;
    medianD += `${s === 0 ? 'M' : 'L'} ${x(s)} ${y(med)} `;
  }
  g.appendChild(ns('path', { d: medianD, fill: 'none', stroke: 'var(--ink)', 'stroke-width': 2 }));

  // Target line at backlog * mid-scope
  const targetMid = p.backlog * (1 + (p.scopeMin + p.scopeMax) / 2);
  g.appendChild(ns('line', {
    x1: 0, y1: y(targetMid), x2: innerW, y2: y(targetMid),
    stroke: 'var(--p95)', 'stroke-width': 1.5, 'stroke-dasharray': '6 4'
  }));
  const targetLbl = ns('text', { x: innerW - 6, y: y(targetMid) - 6, 'text-anchor': 'end', class: 'axis-label', fill: 'var(--p95)' });
  targetLbl.setAttribute('font-weight', '600');
  targetLbl.textContent = `cel: ${targetMid.toFixed(0)} elem. (backlog + scope creep)`;
  g.appendChild(targetLbl);

  // Sept 30 marker vertical line
  const daysToSept = (SEPT_END - p.startDate) / 86400000;
  const sprintsToSept = daysToSept / SPRINT_DAYS;
  if (sprintsToSept >= 0 && sprintsToSept <= maxSprint) {
    const xs = x(sprintsToSept);
    g.appendChild(ns('line', { x1: xs, y1: 0, x2: xs, y2: innerH, stroke: 'var(--navy)', 'stroke-width': 1.5, 'stroke-dasharray': '4 4' }));
    const lbl = ns('text', { x: xs + 4, y: 14, class: 'axis-label', fill: 'var(--navy)' });
    lbl.setAttribute('font-weight', '600');
    lbl.textContent = '30 wrz 2026';
    g.appendChild(lbl);
  }

  // x ticks
  const xStep = Math.max(1, Math.ceil(maxSprint / 8));
  for (let s = 0; s <= maxSprint; s += xStep) {
    const xx = x(s);
    const date = dateAfterSprints(p.startDate, s);
    const t1 = ns('text', { x: xx, y: innerH + 18, 'text-anchor': 'middle', class: 'axis-label' });
    t1.textContent = `s${s}`;
    g.appendChild(t1);
    const t2 = ns('text', { x: xx, y: innerH + 32, 'text-anchor': 'middle', class: 'axis-label' });
    t2.textContent = formatDateShort(date);
    t2.setAttribute('font-size', '10');
    g.appendChild(t2);
  }

  const yTitle = ns('text', { class: 'axis-label' });
  yTitle.setAttribute('transform', `translate(-42, ${innerH/2}) rotate(-90)`);
  yTitle.setAttribute('text-anchor', 'middle');
  yTitle.setAttribute('font-weight', '600');
  yTitle.textContent = 'Elementy ukończone';
  g.appendChild(yTitle);

  // Crosshair tooltip
  const hitArea = ns('rect', { x: 0, y: 0, width: innerW, height: innerH, fill: 'transparent' });
  hitArea.addEventListener('mousemove', e => {
    const rect = svg.getBoundingClientRect();
    const scale = rect.width / W;
    const px = (e.clientX - rect.left) / scale - margin.left;
    if (px < 0 || px > innerW) return;
    const s = Math.round((px / innerW) * maxSprint);
    const arr = perSprint[s];
    if (!arr || !arr.length) return;
    const med = arr[Math.floor(0.5 * arr.length)] || 0;
    const lo = arr[Math.floor(0.15 * arr.length)] || 0;
    const hi = arr[Math.floor(0.85 * arr.length)] || 0;
    const date = dateAfterSprints(p.startDate, s);
    showTip(`Sprint ${s} · ${formatDateShort(date)}
Mediana: ${med.toFixed(1)}
P15–P85: ${lo.toFixed(1)} – ${hi.toFixed(1)}`, e);
  });
  hitArea.addEventListener('mouseleave', hideTip);
  g.appendChild(hitArea);

  svg.appendChild(g);
}

/* ---- Sept 30 distribution ---- */
function renderSept(svg, itemsBySept, percentiles) {
  clearSvg(svg);
  const W = 800, H = 240;
  const margin = { top: 24, right: 24, bottom: 50, left: 56 };
  const innerW = W - margin.left - margin.right;
  const innerH = H - margin.top - margin.bottom;

  const min = Math.floor(itemsBySept[0]);
  const max = Math.ceil(itemsBySept[itemsBySept.length - 1]);
  const binCount = Math.min(30, Math.max(6, max - min + 1));
  const binSize = (max - min) / binCount || 1;
  const bins = new Array(binCount).fill(0);
  for (const v of itemsBySept) {
    const idx = Math.min(binCount - 1, Math.floor((v - min) / binSize));
    bins[idx]++;
  }
  const maxCount = Math.max(...bins);
  const barW = innerW / binCount;

  const g = ns('g', { transform: `translate(${margin.left},${margin.top})` });

  // grid
  for (let i = 0; i <= 4; i++) {
    const yc = (i / 4) * innerH;
    const val = Math.round((1 - i/4) * maxCount);
    g.appendChild(ns('line', { x1: 0, y1: yc, x2: innerW, y2: yc, class: 'grid-line' }));
    const t = ns('text', { x: -8, y: yc + 4, 'text-anchor': 'end', class: 'axis-label' });
    t.textContent = formatNumber(val);
    g.appendChild(t);
  }

  const itemsP50 = percentiles.itemsP50;
  const itemsP85 = percentiles.itemsP85;

  bins.forEach((c, i) => {
    const h = (c / maxCount) * innerH;
    const x = i * barW;
    const binLow = min + i * binSize;
    const binHigh = min + (i+1) * binSize;
    const binCenter = (binLow + binHigh) / 2;
    // color: blue if at or above P85, lighter if below
    const colored = binCenter >= itemsP85 - binSize/2;
    const rect = ns('rect', {
      x: x + 1, y: innerH - h,
      width: Math.max(1, barW - 2), height: h,
      fill: colored ? 'var(--navy)' : 'var(--navy-soft)',
      opacity: colored ? 0.85 : 0.85,
    });
    rect.addEventListener('mouseenter', e => {
      rect.setAttribute('opacity', '1');
      showTip(`${binLow.toFixed(1)}–${binHigh.toFixed(1)} elem.
${c} symulacji (${(c/itemsBySept.length*100).toFixed(1)}%)`, e);
    });
    rect.addEventListener('mousemove', positionTip);
    rect.addEventListener('mouseleave', () => { rect.setAttribute('opacity', '0.85'); hideTip(); });
    g.appendChild(rect);
  });

  // x ticks
  const ticks = 6;
  for (let i = 0; i <= ticks; i++) {
    const val = min + (i/ticks) * (max - min);
    const xx = (i/ticks) * innerW;
    const t = ns('text', { x: xx, y: innerH + 18, 'text-anchor': 'middle', class: 'axis-label' });
    t.textContent = val.toFixed(0);
    g.appendChild(t);
  }

  // P85 line
  const p85x = ((itemsP85 - min) / (max - min)) * innerW;
  g.appendChild(ns('line', {
    x1: p85x, y1: 0, x2: p85x, y2: innerH,
    stroke: 'var(--p85)', 'stroke-width': 2, 'stroke-dasharray': '4 4'
  }));
  const p85lbl = ns('text', { x: p85x + 4, y: 14, class: 'axis-label', fill: 'var(--p85)' });
  p85lbl.setAttribute('font-weight', '600');
  p85lbl.textContent = `P85: ${itemsP85.toFixed(1)} elem.`;
  g.appendChild(p85lbl);

  // P50 marker
  const p50x = ((itemsP50 - min) / (max - min)) * innerW;
  g.appendChild(ns('line', {
    x1: p50x, y1: 0, x2: p50x, y2: innerH,
    stroke: 'var(--p50)', 'stroke-width': 2, 'stroke-dasharray': '4 4'
  }));
  const p50lbl = ns('text', { x: p50x + 4, y: 28, class: 'axis-label', fill: 'var(--p50)' });
  p50lbl.setAttribute('font-weight', '600');
  p50lbl.textContent = `P50: ${itemsP50.toFixed(1)}`;
  g.appendChild(p50lbl);

  const axisTitle = ns('text', { x: innerW / 2, y: innerH + 40, 'text-anchor': 'middle', class: 'axis-label' });
  axisTitle.setAttribute('font-weight', '600');
  axisTitle.textContent = 'Elementy ukończone do 30 września 2026';
  g.appendChild(axisTitle);

  svg.appendChild(g);
}

/* =============================================================
   ORCHESTRATION
   ============================================================= */

function updateUI(result, p) {
  // throughput average
  const thrAvg = avg(p.throughput);
  document.getElementById('v-thr-avg').textContent = thrAvg.toFixed(1);

  // header meta
  document.getElementById('m-runs').textContent = formatNumber(p.runs);
  document.getElementById('m-time').textContent = `${(result.timeMs).toFixed(0)} ms`;
  document.getElementById('m-start').textContent = formatDateShort(p.startDate);
  document.getElementById('m-backlog').textContent = `${p.backlog} elem.`;

  // result cards
  const p50Date = dateAfterSprints(p.startDate, result.p50);
  const p85Date = dateAfterSprints(p.startDate, result.p85);
  const p95Date = dateAfterSprints(p.startDate, result.p95);
  document.getElementById('card-p50-date').textContent = formatDate(p50Date);
  document.getElementById('card-p85-date').textContent = formatDate(p85Date);
  document.getElementById('card-p95-date').textContent = formatDate(p95Date);
  document.getElementById('card-p50-sprints').textContent = `${result.p50} sprintów od startu (avg ${result.avg.toFixed(1)})`;
  document.getElementById('card-p85-sprints').textContent = `${result.p85} sprintów od startu`;
  document.getElementById('card-p95-sprints').textContent = `${result.p95} sprintów od startu`;

  const deltaP85vsP50 = ((p85Date - p50Date) / 86400000 / 7).toFixed(0);
  document.getElementById('card-p50-delta').textContent = `± ${(result.sprints[Math.floor(result.sprints.length*0.75)] - result.p50)} sprintów`;

  document.getElementById('card-sept-items').textContent = result.itemsP50.toFixed(0);
  document.getElementById('card-sept-band').textContent = `P85: ${result.itemsP85.toFixed(1)} elem.  ·  P50: ${result.itemsP50.toFixed(1)} elem.`;

  // render charts
  renderHistogram(document.getElementById('hist-svg'), result.sprints, p, result);
  renderCDF(document.getElementById('cdf-svg'), result.sprints, p, result);
  renderFan(document.getElementById('fan-svg'), result.traces, p, result);
  renderSept(document.getElementById('sept-svg'), result.itemsBySept, result);

  // answers
  document.getElementById('ans-scope').textContent = `${(p.scopeMin*100).toFixed(0)}–${(p.scopeMax*100).toFixed(0)}%`;
  document.getElementById('ans-vac').textContent = `−${((1-p.vacFactor)*100).toFixed(0)}% przez ${p.vacSprints} sprinty`;
  document.getElementById('ans-seasonal').textContent = `−${((1-p.seasonalFactor)*100).toFixed(0)}% od sprintu ${p.seasonalFrom}`;

  const baseDate = dateAfterSprints(p.startDate, result.baseline.p50);
  document.getElementById('ans-base-date').innerHTML = `${formatDate(baseDate)} ${result.baseline.p50} sprintów · bez scope, urlopów, napraw`;

  document.getElementById('ans-q1-p50').innerHTML = `${formatDate(p50Date)} ${result.p50} sprintów`;
  document.getElementById('ans-q1-p85').innerHTML = `${formatDate(p85Date)} ${result.p85} sprintów`;
  document.getElementById('ans-q1-p95').innerHTML = `${formatDate(p95Date)} ${result.p95} sprintów`;

  document.getElementById('ans-recommend').innerHTML = `Wobec zarządu / klienta zobowiązuj się na datę ${formatDate(p85Date)} (P85); ${formatDate(p95Date)} (P95) trzymaj jako wewnętrzny bufor bezpieczeństwa. Mediana ${formatDate(p50Date)} jest scenariuszem optymistycznym — komitment na nią jest ryzykowny.`;

  document.getElementById('ans-q2-p95').innerHTML = `${result.itemsP95.toFixed(0)} elem. (95% pewności, że dostarczymy ≥ tyle)`;
  document.getElementById('ans-q2-p85').innerHTML = `${result.itemsP85.toFixed(0)} elem. (85% pewności)`;
  document.getElementById('ans-q2-p50').innerHTML = `${result.itemsP50.toFixed(0)} elem. (scenariusz medialny)`;
  document.getElementById('ans-q2-avg').innerHTML = `${result.itemsAvg.toFixed(1)} elem. z ${formatNumber(p.runs)} symulacji`;

  document.getElementById('ans-q2-text').innerHTML = `Realistycznie obiecuj ${result.itemsP85.toFixed(0)} elementów do końca września przy 85% pewności. Jest to ${(result.itemsP85/p.backlog*100).toFixed(0)}% oryginalnego backlogu (${p.backlog} elem.). Pamiętaj, że pierwsze 4 sprinty stracimy w dużej mierze na urlopy, a w piątym dochodzi obciążenie naprawami sezonowymi.`;

  // footer
  const now = new Date();
  document.getElementById('foot-runs').textContent = formatNumber(p.runs);
  document.getElementById('foot-time').textContent = `${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
  document.getElementById('last-updated').textContent = `aktualizacja: ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
}

function recalc() {
  const p = readParams();
  // sync min/max scope sliders
  if (p.scopeMin > p.scopeMax) {
    document.getElementById('i-scope-max').value = p.scopeMin;
    p.scopeMax = p.scopeMin;
  }
  // update live labels
  document.getElementById('v-backlog').textContent = p.backlog;
  document.getElementById('v-scope-min').textContent = (p.scopeMin*100).toFixed(0);
  document.getElementById('v-scope-max').textContent = (p.scopeMax*100).toFixed(0);
  document.getElementById('v-vac').textContent = ((1-p.vacFactor)*100).toFixed(0);
  document.getElementById('v-vac-sprints').textContent = p.vacSprints;
  document.getElementById('v-seasonal').textContent = ((1-p.seasonalFactor)*100).toFixed(0);
  document.getElementById('v-seasonal-from').textContent = p.seasonalFrom;
  document.getElementById('v-runs').textContent = formatNumber(p.runs);

  // run
  document.body.classList.add('is-computing');
  // run async so UI updates first
  setTimeout(() => {
    const result = runMonteCarlo(p);
    updateUI(result, p);
    document.body.classList.remove('is-computing');
  }, 10);
}

// debounce for input events
let debounceTimer = null;
function scheduleRecalc() {
  clearTimeout(debounceTimer);
  debounceTimer = setTimeout(recalc, 180);
}

// Bind inputs
['i-backlog','i-start','i-throughput','i-scope-min','i-scope-max',
 'i-vac','i-vac-sprints','i-seasonal','i-seasonal-from','i-runs'].forEach(id => {
  const el = document.getElementById(id);
  el.addEventListener('input', scheduleRecalc);
  el.addEventListener('change', scheduleRecalc);
});

document.getElementById('btn-run').addEventListener('click', recalc);
document.getElementById('btn-reset').addEventListener('click', () => {
  document.getElementById('i-backlog').value = 62;
  document.getElementById('i-start').value = '2026-07-01';
  document.getElementById('i-throughput').value = '5, 4, 4, 5, 6, 4, 2, 3, 2, 5, 6';
  document.getElementById('i-scope-min').value = 20;
  document.getElementById('i-scope-max').value = 30;
  document.getElementById('i-vac').value = 50;
  document.getElementById('i-vac-sprints').value = 4;
  document.getElementById('i-seasonal').value = 25;
  document.getElementById('i-seasonal-from').value = 5;
  document.getElementById('i-runs').value = 10000;
  recalc();
});

// initial
recalc();
